-- "The Office" themed sample database for squix.
-- Created by `squix example`.

PRAGMA foreign_keys = ON;

-- Departments
CREATE TABLE departments (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    name TEXT NOT NULL,
    location TEXT NOT NULL,
    budget REAL,
    head_count INTEGER,
    metadata TEXT,
    config TEXT
);

-- Employees (many columns for overflow/scroll testing)
CREATE TABLE employees (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    first_name TEXT NOT NULL,
    last_name TEXT NOT NULL,
    position TEXT NOT NULL,
    email TEXT NOT NULL,
    phone TEXT,
    date_of_birth TEXT,
    hire_date TEXT NOT NULL,
    salary REAL,
    office_number TEXT,
    department_id INTEGER,
    reports_to INTEGER,
    status TEXT,
    favorite_snack TEXT,
    hobby TEXT,
    car TEXT,
    favorite_catchphrase TEXT,
    linkedin_profile TEXT,
    skills TEXT,
    performance_rating REAL,
    bio TEXT,
    preferences TEXT,
    FOREIGN KEY (department_id) REFERENCES departments(id),
    FOREIGN KEY (reports_to) REFERENCES employees(id)
);

-- Timesheets
CREATE TABLE timesheets (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    employee_id INTEGER,
    task_name TEXT NOT NULL,
    date_worked TEXT NOT NULL,
    hours_worked REAL NOT NULL,
    description TEXT,
    billable INTEGER DEFAULT 1,
    tags TEXT,
    FOREIGN KEY (employee_id) REFERENCES employees(id)
);

